args.cypher:
MATCH (aas:AssetAdministrationShell)-[:HAS_SUBMODEL]->(sm:Submodel)
WHERE EXISTS {
  MATCH (sm)-[:HAS_SEMANTIC_ID]->(:SemanticConcept {id: 'https://admin-shell.io/idta/SubmodelTemplate/technicaldataagv/1/0'})
}
RETURN aas.idShort, aas.id

MATCH (aas:AssetAdministrationShell)-[:HAS_SUBMODEL]->(sm:Submodel)
WHERE EXISTS {
  MATCH (sm)-[:HAS_SEMANTIC_ID]->(:SemanticConcept {id: 'https://admin-shell.io/idta/SubmodelTemplate/technicaldataagv/1/0'})
}
MATCH (sm)-[:HAS_ELEMENT*]->(p:Property)
RETURN aas.idShort, p.idShort, p.value, p.valueType

MATCH (aas:AssetAdministrationShell)-[:HAS_SUBMODEL]->(sm:Submodel)
WHERE EXISTS {
  MATCH (sm)-[:HAS_SEMANTIC_ID]->(sc:SemanticConcept {id: $transport_robot_semanticId})
}
RETURN sm.idShort AS submodel_idShort, sm.id AS submodel_id
LIMIT 20
